import { useEffect, useState } from 'react'
import type { RuntimeEvent } from '../../shared/ipc.js'

export function useDesktop() {
  if (typeof window === 'undefined' || !window.urDesktop) {
    return null
  }
  return window.urDesktop
}

export function useRuntimeEvents(callback: (event: RuntimeEvent) => void) {
  const desktop = useDesktop()
  useEffect(() => {
    if (!desktop) return
    return desktop.subscribe('runtime:event', callback)
  }, [desktop, callback])
}

import { useCallback, useEffect, useRef, useState } from 'react'
import { Card } from '../components/Card.js'
import { useDesktop, useRuntimeEvents } from '../hooks/useDesktop.js'
import type { RuntimeEvent } from '../../shared/ipc.js'

type Message = {
  id: string
  role: 'user' | 'assistant'
  content: string
}

export function ChatPage() {
  const desktop = useDesktop()
  const [projectRoot, setProjectRoot] = useState('')
  const [sessionId, setSessionId] = useState<string | null>(null)
  const [input, setInput] = useState('')
  const [messages, setMessages] = useState<Message[]>([])
  const [events, setEvents] = useState<RuntimeEvent[]>([])
  const [status, setStatus] = useState<'idle' | 'running' | 'paused'>('idle')
  const scrollRef = useRef<HTMLDivElement>(null)

  const handleEvent = useCallback((event: RuntimeEvent) => {
    setEvents(prev => [...prev, event])
    if (event.type === 'message_created') {
      const e = event as { role: 'user' | 'assistant'; content: string }
      setMessages(prev => {
        if (prev.some(m => m.id === `${event.timestamp}-${event.type}`)) return prev
        return [
          ...prev,
          {
            id: `${event.timestamp}-${event.type}`,
            role: e.role,
            content: e.content,
          },
        ]
      })
    }
    if (event.type === 'run_started') setStatus('running')
    if (event.type === 'run_finished') setStatus('idle')
    if (event.type === 'run_failed') setStatus('idle')
  }, [])

  useRuntimeEvents(handleEvent)

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' })
  }, [messages, events])

  const openProject = async () => {
    if (!desktop || !projectRoot) return
    await desktop.openProject(projectRoot)
  }

  const startRun = async () => {
    if (!desktop || !projectRoot) return
    const session = await desktop.startRun(projectRoot)
    setSessionId(session.sessionId)
    setStatus('running')
  }

  const send = async () => {
    if (!desktop || !sessionId || !input.trim()) return
    await desktop.sendMessage(sessionId, input.trim())
    setInput('')
  }

  const stop = async () => {
    if (!desktop || !sessionId) return
    await desktop.stopRun(sessionId)
    setStatus('idle')
  }

  const pause = async () => {
    if (!desktop || !sessionId) return
    await desktop.pauseRun(sessionId)
    setStatus('paused')
  }

  const resume = async () => {
    if (!desktop || !sessionId) return
    await desktop.resumeRun(sessionId)
    setStatus('running')
  }

  return (
    <div className="page chat-page">
      <div className="chat-header">
        <h1 className="page-title">Chat</h1>
        <div className="chat-controls">
          <input
            className="input project-input"
            placeholder="Project root path..."
            value={projectRoot}
            onChange={e => setProjectRoot(e.target.value)}
          />
          <button className="button button-secondary" onClick={openProject}>
            Open
          </button>
          <button className="button" onClick={startRun} disabled={!projectRoot || status !== 'idle'}>
            Start run
          </button>
        </div>
      </div>

      <div className="chat-stream" ref={scrollRef}>
        {messages.length === 0 && events.length === 0 && (
          <div className="empty-state">
            <div className="empty-state-icon">💬</div>
            <p>Open a project, start a run, and send a message.</p>
          </div>
        )}

        {messages.map(message => (
          <div key={message.id} className={`message ${message.role}`}>
            <div className="message-meta">{message.role === 'user' ? 'You' : 'UR'}</div>
            <div className="message-body">{message.content}</div>
          </div>
        ))}

        {events
          .filter(e => e.type === 'model_stream' || e.type === 'tool_call_started' || e.type === 'tool_call_finished')
          .slice(-5)
          .map((event, i) => (
            <div key={`${event.timestamp}-${i}`} className="event-item">
              <span className="event-type">{event.type}</span>
              <span className="event-payload">
                {event.type === 'model_stream' ? (event as { delta?: string }).delta ?? '' : JSON.stringify(event)}
              </span>
            </div>
          ))}
      </div>

      <Card title="Composer">
        <div className="composer">
          <input
            className="input"
            placeholder="Ask UR to do something..."
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault()
                send()
              }
            }}
            disabled={status !== 'running' || !sessionId}
          />
          <div className="composer-actions">
            {status === 'running' ? (
              <>
                <button className="button button-secondary" onClick={pause}>
                  Pause
                </button>
                <button className="button button-secondary" onClick={stop}>
                  Stop
                </button>
              </>
            ) : status === 'paused' ? (
              <button className="button" onClick={resume}>
                Resume
              </button>
            ) : null}
            <button
              className="button"
              onClick={send}
              disabled={status !== 'running' || !sessionId || !input.trim()}
            >
              Send
            </button>
          </div>
        </div>
      </Card>
    </div>
  )
}

