  border: 1px solid #333;
  border-radius: 6px;
  padding: 10px 12px;
  color: #e5e5e5;
  font-size: 13px;
  outline: none;
}

.input:focus {
  border-color: #4f46e5;
}

.input:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  background: #4f46e5;
  color: #fff;
  border: none;
  border-radius: 6px;
  padding: 8px 14px;
  font-size: 13px;
  font-weight: 500;
