  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  color: #525252;
  text-align: center;
}

.empty-state-icon {
  font-size: 40px;
  margin-bottom: 12px;
  opacity: 0.5;
}

.list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

