  color: #d4d4d4;
  font-size: 13px;
}

.badge {
  display: inline-flex;
  align-items: center;
  padding: 2px 8px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 500;
  background: #262626;
  color: #a3a3a3;
}

