.chat-page {
  display: flex;
  flex-direction: column;
  padding: 0;
  height: 100%;
}

.chat-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 24px;
  border-bottom: 1px solid #262626;
  background: #141414;
}

.chat-header .page-title {
  margin: 0;
  font-size: 18px;
}

.chat-controls {
  display: flex;
  align-items: center;
  gap: 8px;
}

.project-input {
  width: 260px;
}

.chat-stream {
  flex: 1;
  overflow-y: auto;
  padding: 24px 32px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.message {
  max-width: 80%;
  border-radius: 10px;
  padding: 12px 16px;
  font-size: 13px;
  line-height: 1.5;
}

.message.user {
  align-self: flex-end;
  background: #4f46e5;
  color: #fff;
}

.message.assistant {
  align-self: flex-start;
  background: #1f1f1f;
  border: 1px solid #333;
}

.message-meta {
  font-size: 11px;
  font-weight: 600;
  margin-bottom: 4px;
  opacity: 0.7;
}

.event-item {
  align-self: flex-start;
  background: #141414;
  border: 1px solid #262626;
  border-radius: 8px;
  padding: 8px 12px;
  font-size: 12px;
  color: #a3a3a3;
  display: flex;
  flex-direction: column;
  gap: 4px;
  max-width: 90%;
}

.event-type {
  color: #4f46e5;
  font-weight: 600;
  text-transform: uppercase;
  font-size: 10px;
}

.event-payload {
  font-family: 'SFMono-Regular', Consolas, monospace;
  white-space: pre-wrap;
  word-break: break-word;
}

.composer {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.composer-actions {
  display: flex;
  justify-content: flex-end;
  gap: 8px;
}

