export async function startRun(
  projectRoot: string,
  options: { useWorktree?: boolean; branch?: string } = {},
): Promise<{ runId: string; sessionId: string; projectRoot: string; worktreeRoot?: string }> {
  const project = getProject(projectRoot)
  const runId = randomUUID()

  // Create the run record early so the permission hook can reference it.
  const run: RuntimeRun = {
    runId,
    session: null as unknown as RuntimeSession,
    projectRoot,
    worktreeRoot: undefined,
    changedFiles: new Set(),
    status: 'idle',
  }
  runs.set(runId, run)

  let worktree: Worktree | undefined
  if (options.useWorktree) {
    worktree = await createIsolatedWorktree(project.root, options.branch).catch(
      () => undefined,
    )
    run.worktreeRoot = worktree?.root
  }

  createTask(runId, 'task-1', {
    index: 1,
    title: 'Process user request',
    description: 'Handle the current user prompt',
    dependencies: [],
  })

  await ensureConnectorClientsConnected(projectRoot)

  const canUseTool: import('@ur/agent-runtime').CanUseToolFn = async (
    tool,
    input,
  ) => {
    // Read-only tools (including read-only MCP tools) do not require approval.
    if (tool.isReadOnly(input)) {
      return { behavior: 'allow' } as import('@ur/agent-runtime').PermissionDecision<Record<string, unknown>>
    }
    // MCP side-effect tools require explicit user approval.
    if (tool.isMcp) {
      const approved = await requestApproval(runId, tool.name, input as Record<string, unknown>, 'task-1')
      return approved
        ? ({ behavior: 'allow' } as import('@ur/agent-runtime').PermissionDecision<Record<string, unknown>>)
        : ({ behavior: 'deny', message: 'User denied MCP tool use' } as import('@ur/agent-runtime').PermissionDecision<Record<string, unknown>>)
    }
    // Built-in tools run under the existing permission/approval path.
    return { behavior: 'allow' } as import('@ur/agent-runtime').PermissionDecision<Record<string, unknown>>
  }

  const session = await createSession(project, { sessionId: runId, canUseTool })
  run.session = session
  sessions.set(session.sessionId, session)
  if (worktree) {
    setWorktree(runId, worktree)
  }
  return {
    runId,
    sessionId: session.sessionId,
    projectRoot,
    worktreeRoot: worktree?.root,
  }
}

