  tool,
  input,
) => {
  const evaluation = await evaluateToolUse(
    { runId, projectRoot, worktreeRoot: run.worktreeRoot },
    {
      name: tool.name,
      isMcp: tool.isMcp,
      isReadOnly: (i?) => tool.isReadOnly(i ?? input),
