import * as path from 'node:path'
import { promises as fs } from 'node:fs'
import * as os from 'node:os'

export interface RunRecord {
  runId: string
  sessionId: string
  projectRoot: string
  projectName: string
  worktreeRoot?: string
  startedAt: string
  finishedAt?: string
  status: 'running' | 'finished' | 'failed' | 'stopped'
  title?: string
  providerId?: string
  modelId?: string
  changedFiles: string[]
  costUsd?: number
  transcriptPath: string
  reportPath?: string
}

const desktopDir = path.join(os.homedir(), '.ur', 'desktop')
const indexPath = path.join(desktopDir, 'history.jsonl')
const transcriptsDir = path.join(desktopDir, 'transcripts')

async function ensureDirs(): Promise<void> {
  await fs.mkdir(desktopDir, { recursive: true })
  await fs.mkdir(transcriptsDir, { recursive: true })
}

function transcriptPath(runId: string): string {
  return path.join(transcriptsDir, `${runId}.jsonl`)
}

export async function appendRun(record: RunRecord): Promise<void> {
  await ensureDirs()
  const line = JSON.stringify(record)
  await fs.appendFile(indexPath, `${line}\n`, 'utf-8')
}

export async function updateRun(
  runId: string,
  patch: Partial<RunRecord>,
): Promise<void> {
  const records = await listAllRuns()
  const idx = records.findIndex(r => r.runId === runId)
  if (idx === -1) {
    // If the run is not in the index yet, append it with the patch merged.
    await appendRun({
      ...(patch as RunRecord),
      runId,
      transcriptPath: patch.transcriptPath ?? transcriptPath(runId),
      changedFiles: patch.changedFiles ?? [],
    })
    return
  }
  records[idx] = { ...records[idx], ...patch }
  await writeIndex(records)
}

export async function listRuns(filters?: {
  projectRoot?: string
  status?: RunRecord['status']
  limit?: number
}): Promise<RunRecord[]> {
  let records = await listAllRuns()
  if (filters?.projectRoot) {
    records = records.filter(r => r.projectRoot === filters.projectRoot)
  }
  if (filters?.status) {
    records = records.filter(r => r.status === filters.status)
  }
  records.sort((a, b) => Date.parse(b.startedAt) - Date.parse(a.startedAt))
  if (filters?.limit) {
    records = records.slice(0, filters.limit)
  }
  return records
}

export async function getRun(runId: string): Promise<RunRecord | undefined> {
  const records = await listAllRuns()
  return records.find(r => r.runId === runId)
}

export async function deleteRun(runId: string): Promise<boolean> {
  const records = await listAllRuns()
  const idx = records.findIndex(r => r.runId === runId)
  if (idx === -1) return false
  records.splice(idx, 1)
  await writeIndex(records)
  try {
    await fs.unlink(transcriptPath(runId))
  } catch {
    // ignore
  }
  return true
}

export async function appendEvent(runId: string, event: Record<string, unknown>): Promise<void> {
  await ensureDirs()
  const file = transcriptPath(runId)
  await fs.appendFile(file, `${JSON.stringify(event)}\n`, 'utf-8')
}

export async function readTranscript(runId: string): Promise<Record<string, unknown>[]> {
  const file = transcriptPath(runId)
  try {
    const content = await fs.readFile(file, 'utf-8')
    return content
      .split('\n')
      .filter(Boolean)
      .map(line => JSON.parse(line) as Record<string, unknown>)
  } catch (err) {
    if ((err as NodeJS.ErrnoException).code === 'ENOENT') {
      return []
    }
    throw err
  }
}

async function listAllRuns(): Promise<RunRecord[]> {
  try {
    const content = await fs.readFile(indexPath, 'utf-8')
    const records: RunRecord[] = []
    for (const line of content.split('\n')) {
      if (!line.trim()) continue
      try {
        records.push(JSON.parse(line) as RunRecord)
      } catch {
        // skip malformed lines
      }
    }
    return records
  } catch (err) {
    if ((err as NodeJS.ErrnoException).code === 'ENOENT') {
      return []
    }
    throw err
  }
}

async function writeIndex(records: RunRecord[]): Promise<void> {
  await ensureDirs()
  const lines = records.map(r => JSON.stringify(r)).join('\n')
  await fs.writeFile(indexPath, lines ? `${lines}\n` : '', 'utf-8')
}

import { readApprovalLog, type ApprovalLogEntry } from './safety/approvalLog.js'

export interface RunReport {
  runId: string
  projectRoot: string
  projectName?: string
  title?: string
  startedAt?: string
  finishedAt?: string
  status?: string
  providerId?: string
  modelId?: string
  changedFiles: string[]
  costUsd?: number
  verifiedChanges: { file: string; description: string }[]
  unverifiedClaims: { claim: string; reason: string }[]
  testsRun: { command: string; passed: boolean; output?: string }[]
  failedChecks: { check: string; reason: string }[]
  remainingIssues: { issue: string; severity: string }[]
  approvals: ApprovalLogEntry[]
}

const TEST_PATTERNS = [
  /\b(npm test|yarn test|pnpm test|bun test)\b/i,
  /\b(vitest|jest|pytest|mocha|tap|ava)\b/i,
  /\b(go test|rake test|bundle exec rspec)\b/i,
]

function isTestCommand(command: string): boolean {
  return TEST_PATTERNS.some(p => p.test(command))
}

function eventType(event: Record<string, unknown>): string {
  return String(event.type ?? '')
}

export async function buildRunReport(
  projectRoot: string,
  runId: string,
  events: Record<string, unknown>[],
  opts: {
    projectName?: string
    title?: string
    startedAt?: string
    finishedAt?: string
    status?: string
    providerId?: string
    modelId?: string
    costUsd?: number
    changedFiles?: string[]
  } = {},
): Promise<RunReport> {
  const verifiedChanges: { file: string; description: string }[] = []
  const unverifiedClaims: { claim: string; reason: string }[] = []
  const testsRun: { command: string; passed: boolean; output?: string }[] = []
  const failedChecks: { check: string; reason: string }[] = []
  const remainingIssues: { issue: string; severity: string }[] = []

  let verificationPassed = false
  let changedFiles: string[] = opts.changedFiles ?? []

  for (const event of events) {
    const type = eventType(event)
    switch (type) {
      case 'verification_completed': {
        const passed = event.passed === true
        verificationPassed = passed
        if (passed) {
          verifiedChanges.push({
            file: changedFiles[0] ?? 'project',
            description: String(event.message ?? 'Verification passed'),
          })
        } else {
          failedChecks.push({
            check: 'Verification',
            reason: String(event.message ?? 'Verification failed'),
          })
        }
        break
      }
      case 'changed_files': {
        if (Array.isArray(event.files)) {
          changedFiles = [...new Set([...changedFiles, ...(event.files as string[])])]
        }
        break
      }
      case 'command_finished': {
        const command = String((event as { command?: string }).command ?? '')
        const output = String(event.output ?? '')
        const exitCode = Number(event.exitCode ?? 0)
        if (command && isTestCommand(command)) {
          testsRun.push({ command, passed: exitCode === 0, output })
        }
        if (exitCode !== 0 && command) {
          failedChecks.push({ check: command, reason: `Exit code ${exitCode}` })
        }
        break
      }
      case 'task_failed': {
        remainingIssues.push({
          issue: String(event.error ?? 'Task failed'),
          severity: 'high',
        })
        break
      }
      case 'run_failed': {
        remainingIssues.push({
          issue: String(event.error ?? 'Run failed'),
          severity: 'critical',
        })
        break
      }
      case 'message_created': {
        if (event.role === 'assistant') {
          const content = String(event.content ?? '')
          if (
            /done|finished|completed|implemented/i.test(content) &&
            !verificationPassed
          ) {
            unverifiedClaims.push({
              claim: content.slice(0, 200),
              reason: 'No verification event was recorded for this claim.',
            })
          }
        }
        break
      }
    }
  }

  const approvals = await readApprovalLog(projectRoot).catch(() => [] as ApprovalLogEntry[])

  return {
    runId,
    projectRoot,
    projectName: opts.projectName,
    title: opts.title,
    startedAt: opts.startedAt,
    finishedAt: opts.finishedAt,
    status: opts.status,
    providerId: opts.providerId,
    modelId: opts.modelId,
    costUsd: opts.costUsd,
    changedFiles,
    verifiedChanges,
    unverifiedClaims,
    testsRun,
    failedChecks,
    remainingIssues,
    approvals,
  }
}

export function buildReportMarkdown(report: RunReport): string {
  const lines: string[] = [
    `# Run Report`,
    '',
    `- **Run ID:** ${report.runId}`,
    `- **Project:** ${report.projectName ?? report.projectRoot}`,
    `- **Status:** ${report.status ?? 'unknown'}`,
    `- **Started:** ${report.startedAt ?? '-'}`,
    `- **Finished:** ${report.finishedAt ?? '-'}`,
    `- **Provider/model:** ${report.providerId ?? '-'} / ${report.modelId ?? '-'}`,
    report.costUsd !== undefined ? `- **Cost:** $${report.costUsd.toFixed(6)}` : '',
    '',
    `## Verified changes`,
    ...(report.verifiedChanges.length
      ? report.verifiedChanges.map(c => `- ${c.file}: ${c.description}`)
      : ['_None_']),
    '',
    `## Unverified claims`,
    ...(report.unverifiedClaims.length
      ? report.unverifiedClaims.map(c => `- ${c.claim}\n  - Reason: ${c.reason}`)
      : ['_None_']),
    '',
    `## Tests run`,
    ...(report.testsRun.length
      ? report.testsRun.map(t => `- \`${t.command}\` ${t.passed ? 'PASS' : 'FAIL'}`)
      : ['_None_']),
    '',
    `## Failed checks`,
    ...(report.failedChecks.length
      ? report.failedChecks.map(c => `- ${c.check}: ${c.reason}`)
      : ['_None_']),
    '',
    `## Remaining issues`,
    ...(report.remainingIssues.length
      ? report.remainingIssues.map(i => `- (${i.severity}) ${i.issue}`)
      : ['_None_']),
    '',
    `## Changed files`,
    ...(report.changedFiles.length ? report.changedFiles.map(f => `- ${f}`) : ['_None_']),
    '',
  ]
  return lines.filter(Boolean).join('\n')
}

export function buildReportJson(report: RunReport): string {
  return JSON.stringify(report, null, 2)
}

