import { spawn } from 'node:child_process'
import path from 'node:path'
import { fileURLToPath } from 'node:url'
import { test, expect } from 'bun:test'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const mainScript = path.join(__dirname, '..', 'dist', 'main', 'main.js')

function waitForOutput(proc, marker, timeoutMs = 10000) {
  return new Promise((resolve, reject) => {
    let output = ''
    const timer = setTimeout(() => {
      cleanup()
      reject(new Error(`Timeout waiting for ${marker}. Output:\n${output}`))
    }, timeoutMs)
    function cleanup() {
      clearTimeout(timer)
      proc.stdout?.off('data', onData)
      proc.stderr?.off('data', onData)
    }
    function onData(chunk) {
      const text = chunk.toString()
      output += text
      if (text.includes(marker)) {
        cleanup()
        resolve(output)
      }
    }
    proc.stdout?.on('data', onData)
    proc.stderr?.on('data', onData)
  })
}

test('packaged electron app starts and reports ready', async () => {
  const proc = spawn('electron', [mainScript, '--smoke-test'], {
    cwd: path.join(__dirname, '..'),
    env: { ...process.env, NODE_ENV: 'production' },
    stdio: ['ignore', 'pipe', 'pipe'],
  })

  let output = ''
  try {
    output = await waitForOutput(proc, 'UR_DESKTOP_READY')
  } finally {
    proc.kill('SIGTERM')
  }

  expect(output).toContain('UR_DESKTOP_READY')
}, 15000)

