function formatDate(iso?: string): string {
  if (!iso) return '-'
  const d = new Date(iso)
  return d.toLocaleString()
}

function statusBadge(status: string): string {
  switch (status) {
    case 'finished':
      return '✓'
    case 'failed':
      return '✗'
    case 'stopped':
      return '■'
    default:
      return '●'
  }
}

